// PRODUCT REGISTRY
// ═══════════════════════════════════════════════════════════════════════════════

export interface Product {
  /** Product identifier (used in code) */
  id: string;
  /** Display name */
  name: string;
  /** Brief description */
  description: string;
  /** Ecosystem layer */
  layer: EcosystemLayer;
  /** Primary domain */
  domain: string;
  /** GitHub repository name */
  repo: string;
  /** GitHub organization */
  githubOrg: "madfam-org" | "madfam";
  /** License type */
  license: LicenseType;
  /** Default port for local development */
  defaultPort?: number;
  /** Whether this product is publicly available */
  isPublic: boolean;
  /** Roadmap phase (1-5) */
  phase: 1 | 2 | 3 | 4 | 5;
}

